parameters.jsCode:
const body = $json.body ?? $json;

const instance = String(body.instance || body.instancia || 'Shkgroup').trim();
const msg = body.data?.message || {};
const text = String(msg.conversation || msg.extendedTextMessage?.text || '').trim();

const lower = text.toLowerCase().trim();

// comando = primeira palavra (on/off)
const command = lower.startsWith('off') ? 'off' : (lower.startsWith('on') ? 'on' : '');

// pega tudo que vem depois do comando (com ou sem espaço) e extrai só dígitos
const after = lower.replace(/^off/i, '').replace(/^on/i, '');
const digits = after.replace(/\D/g, '');

// monta remoteJid
const targetRemoteJid = digits.length >= 10 ? `${digits}@s.whatsapp.net` : '';

return [{
  json: {
    instance,
    adminChatJid: body.data?.key?.remoteJid || '',
    command,
    digits,
    targetRemoteJid,
    lockUntil: '4102444800000'
  }
}];

// Garantir que a chave tenha valores válidos
const instancia = $json.instancia || 'defaultInstancia';
const numero = $json.numero || 'defaultNumero';

// Gerar a chave de forma segura
const chaveRedis = `chat:${instancia}:${numero}:tags`;

// Verifique se $json.tags está preenchido
const tagsArray = $json.tags || [];

return [{
  json: {
    chave: chaveRedis,
    tags: tagsArray
  }
}];

function pickText(j) {
  return (
    j?.data?.message?.conversation ||
    j?.data?.message?.extendedTextMessage?.text ||
    j?.data?.message?.imageMessage?.caption ||
    j?.data?.message?.videoMessage?.caption ||
    j?.data?.message?.documentMessage?.caption ||
    ''
  );
}

const texto = String(pickText($json) || '');
const msg = texto.toLowerCase();

const palavrasCriticas = ['cancelar','raiva','processo','reembolso','chargeback'];

let palavraCritica = '';
for (const p of palavrasCriticas) {
  if (msg.includes(p)) { palavraCritica = p; break; }
}

return [{
  json: {
    ...$json,
    instancia: $json.instancia || 'Shkgroup',
    numero: String($json?.data?.key?.remoteJid || '').split('@')[0],
    nome: $json?.data?.pushName || '',
    mensagem: texto,
    palavraCritica: palavraCritica || 'Sem palavra crítica',
    achou: Boolean(palavraCritica),
  }
}];

// Extrair nota do comando #nota: texto aqui
const mensagem = $json.mensagem;
const nota = mensagem.replace(/^#nota:\s*/, '').trim();

const timestamp = new Date().toISOString();
const dataFormatada = new Date().toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

return {
  instancia: $json.instancia,
  numero: $json.numero,
  nota: nota,
  timestamp: timestamp,
  dataFormatada: dataFormatada
};

// Adicionar nova nota ao histórico
const notasAnteriores = $input.item(0).json.value || '';
const novaNota = $items('Notas Processar Nota')[0].json;

let notasArray = [];
if (notasAnteriores) {
  try {
    notasArray = JSON.parse(notasAnteriores);
  } catch (e) {
    notasArray = [];
  }
}

// Adicionar nova nota
notasArray.push({
  data: novaNota.dataFormatada,
  nota: novaNota.nota
});

// Limitar a 50 últimas notas
if (notasArray.length > 50) {
  notasArray = notasArray.slice(-50);
}

return {
  instancia: novaNota.instancia,
  numero: novaNota.numero,
  notasJSON: JSON.stringify(notasArray),
  ultimaNota: novaNota.nota,
  dataFormatada: novaNota.dataFormatada
};

