const raw = ( $('Webhook').item.json.body.data.message?.conversation 
  || $('Webhook').item.json.body.data.message?.extendedTextMessage?.text 
  || '' ).toString().trim();
const parts = raw.split(/\s+/);
const comando = (parts[0] || '').toLowerCase().replace(/^\//,'');
const numero = (parts[1] || '').replace(/\D/g,'');
const extra = parts.slice(2).join(' ').trim();
const inst = $('Dados2').item.json.instancia ?? 'Shkgroup';
const targetJid = numero ? `${numero}@s.whatsapp.net` : '';

// Parse timeout for "off NUM 2h" / "off NUM 30m"
let timeoutMs = 0;
if (extra) {
  const m = extra.match(/^(\d+)\s*(h|hr|hrs|hora|horas|m|min|mins|minuto|minutos)$/i);
  if (m) {
    const val = parseInt(m[1]);
    const unit = m[2].toLowerCase();
    if (unit.startsWith('h')) timeoutMs = val * 3600 * 1000;
    else timeoutMs = val * 60 * 1000;
  }
}

return [{ json: {
  comando, numero, extra, instancia: inst, targetJid, timeoutMs,
  humanKey: `chat:${inst}:${targetJid}:humanControlUntil`,
  paymentKey: `chat:${inst}:${targetJid}:paymentStatus`,
  optoutKey: `chat:${inst}:${targetJid}:optout`,
  stepKey: `chat:${inst}:${targetJid}:followup_step`,
  notaKey: `chat:${inst}:${targetJid}:notas`
}}];

