const body = $('Webhook').item.json.body;
const data = body?.data || {};
const key = data?.key || {};
const msg = data?.message || {};

const instancia = body?.instance || body?.instancia || 'Shkgroup';
const remoteJid = key?.remoteJid || '';
const phone = remoteJid.replace('@s.whatsapp.net','').replace('@g.us','');
const pushName = data?.pushName || 'Desconhecido';
const msgType = data?.messageType || 'unknown';

let textoMsg = '';
if (msgType === 'conversation') {
  textoMsg = msg.conversation || '';
} else if (msgType === 'extendedTextMessage') {
  textoMsg = msg.extendedTextMessage?.text || '';
} else if (msgType === 'audioMessage') {
  textoMsg = '🎤 [Áudio]';
} else if (msgType === 'imageMessage') {
  textoMsg = '🖼️ [Imagem]' + (msg.imageMessage?.caption ? ': ' + msg.imageMessage.caption : '');
} else if (msgType === 'videoMessage') {
  textoMsg = '🎥 [Vídeo]' + (msg.videoMessage?.caption ? ': ' + msg.videoMessage.caption : '');
} else if (msgType === 'documentMessage') {
  textoMsg = '📄 [Documento]: ' + (msg.documentMessage?.fileName || '');
} else if (msgType === 'stickerMessage') {
  textoMsg = '🎭 [Sticker]';
} else if (msgType === 'reactionMessage') {
  textoMsg = '👍 [Reação]: ' + (msg.reactionMessage?.text || '');
} else {
  textoMsg = `[${msgType}]`;
}

const preview = textoMsg.substring(0, 300);
const hora = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  hour: '2-digit', minute: '2-digit'
}).format(new Date());

const alertText = [
  `📩 *NOVA MENSAGEM DE LEAD*`,
  ``,
  `👤 *Nome:* ${pushName}`,
  `📱 *Número:* +${phone}`,
  `🕐 *Hora:* ${hora}`,
  `📝 *Tipo:* ${msgType}`,
  ``,
  `💬 *Mensagem:*`,
  `${preview || '(sem texto)'}`,
  ``,
  `🤖 A IA já leu e está respondendo automaticamente.`
].join('\n');

return [{ json: { alertText, instancia, remoteJid, phone, pushName } }];

